import React, { useState } from 'react';
import axios from 'axios';

const LoginPage = ({ onLoginSuccess }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);

  const API_URL = "http://localhost:5000";

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const endpoint = isLogin ? '/login' : '/signup';
      const res = await axios.post(`${API_URL}${endpoint}`, { email, password });

      if (isLogin) {
        onLoginSuccess(res.data.email);
      } else {
        alert('Registration successful! Please log in.');
        setIsLogin(true);
        setPassword('');
      }
    } catch (err) {
      setError(err.response?.data?.error || 'Something went wrong. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const backgroundImageUrl = '/fraud-bg.jpg';

  return (
    <div style={{
      display: 'flex',
      minHeight: '100vh',
      background: 'radial-gradient(circle at top left, #2d0b3a, #0f172a 70%)',
      color: 'white',
      fontFamily: "'Inter', sans-serif",
      position: 'relative',
      overflowX: 'hidden',
      overflowY: 'auto'
    }}>
      {/* Top Left Sign In Option */}
      {!showForm && (
        <div style={{
          position: 'absolute',
          top: '2rem',
          left: '2rem',
          zIndex: 100
        }}>
          <button 
            className="glow-button"
            onClick={() => setShowForm(true)}
          >
            Sign In
          </button>
        </div>
      )}

      {/* Main Content Area */}
      <div style={{
        display: 'flex',
        width: '100%',
        transition: 'all 0.8s cubic-bezier(0.4, 0, 0.2, 1)',
        transform: showForm ? 'translateX(0)' : 'translateX(0)'
      }}>

        {/* Left Side: Form (Only visible when showForm is true) */}
        <div style={{
          flex: showForm ? '0 0 50%' : '0 0 0%',
          opacity: showForm ? 1 : 0,
          visibility: showForm ? 'visible' : 'hidden',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          background: 'radial-gradient(circle at top left, #2d0b3a, #0f172a 70%)',
          transition: 'all 0.8s cubic-bezier(0.4, 0, 0.2, 1)',
          padding: showForm ? '2rem' : '0',
          borderRight: showForm ? '1px solid #334155' : 'none',
          zIndex: 50
        }}>
          {showForm && (
            <div style={{
              width: '100%',
              maxWidth: '400px',
              padding: '2.5rem',
              backgroundColor: '#1e293b',
              borderRadius: '1.5rem',
              boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)',
              border: '1px solid #334155'
            }}>
              <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
                <div style={{
                  width: '48px',
                  height: '48px',
                  backgroundColor: '#00f3ff',
                  borderRadius: '12px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  margin: '0 auto 1rem',
                  fontSize: '1.5rem',
                  fontWeight: 'bold',
                  color: '#000',
                  boxShadow: '0 0 15px #00f3ff'
                }}>F</div>
                <h2 style={{ fontSize: '1.875rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>
                  {isLogin ? 'Welcome Back' : 'Create Account'}
                </h2>
                <p style={{ color: '#94a3b8' }}>
                  {isLogin ? 'Enter your credentials to access FraudShield' : 'Join FraudShield to monitor transactions'}
                </p>
              </div>

              <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
                <div>
                  <label style={{ display: 'block', fontSize: '0.875rem', color: '#94a3b8', marginBottom: '0.5rem' }}>Email Address</label>
                  <input
                    type="email"
                    required
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    placeholder="name@company.com"
                    style={{
                      width: '100%',
                      padding: '0.75rem 1rem',
                      backgroundColor: 'rgba(15, 23, 42, 0.6)',
                      border: '1px solid #334155',
                      borderRadius: '0.75rem',
                      color: 'white',
                      outline: 'none',
                      transition: 'border-color 0.2s'
                    }}
                  />
                </div>

                <div>
                  <label style={{ display: 'block', fontSize: '0.875rem', color: '#94a3b8', marginBottom: '0.5rem' }}>Password</label>
                  <input
                    type="password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="••••••••"
                    style={{
                      width: '100%',
                      padding: '0.75rem 1rem',
                      backgroundColor: 'rgba(15, 23, 42, 0.6)',
                      border: '1px solid #334155',
                      borderRadius: '0.75rem',
                      color: 'white',
                      outline: 'none'
                    }}
                  />
                </div>

                {error && (
                  <div style={{
                    padding: '0.75rem',
                    backgroundColor: 'rgba(239, 68, 68, 0.1)',
                    border: '1px solid rgba(239, 68, 68, 0.2)',
                    borderRadius: '0.5rem',
                    color: '#ef4444',
                    fontSize: '0.875rem'
                  }}>{error}</div>
                )}

                <button
                  type="submit"
                  disabled={loading}
                  style={{
                    width: '100%',
                    padding: '0.75rem',
                    backgroundColor: '#00f3ff',
                    color: '#000',
                    border: 'none',
                    borderRadius: '0.75rem',
                    fontWeight: 'bold',
                    fontSize: '1rem',
                    cursor: loading ? 'not-allowed' : 'pointer',
                    transition: 'all 0.2s',
                    marginTop: '0.5rem',
                    boxShadow: '0 0 10px #00f3ff'
                  }}
                >
                  {loading ? 'Processing...' : (isLogin ? 'Sign In' : 'Register')}
                </button>
              </form>

              <div style={{ textAlign: 'center', marginTop: '1.5rem' }}>
                <p style={{ fontSize: '0.875rem', color: '#94a3b8' }}>
                  {isLogin ? "Don't have an account?" : "Already have an account?"}{' '}
                  <button
                    onClick={() => {
                      setIsLogin(!isLogin);
                      setError('');
                    }}
                    style={{
                      background: 'none',
                      border: 'none',
                      color: '#00f3ff',
                      fontWeight: 'bold',
                      cursor: 'pointer',
                      padding: 0
                    }}
                  >
                    {isLogin ? 'Sign Up' : 'Log In'}
                  </button>
                </p>
                <button 
                  onClick={() => setShowForm(false)}
                  style={{
                    background: 'none',
                    border: 'none',
                    color: '#64748b',
                    fontSize: '0.75rem',
                    marginTop: '1rem',
                    cursor: 'pointer'
                  }}
                >
                  ← Back to welcome
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Right Side / Background Image */}
        <div style={{
          flex: showForm ? '0 0 50%' : '0 0 100%',
          position: 'relative',
          transition: 'all 0.8s cubic-bezier(0.4, 0, 0.2, 1)',
          backgroundImage: `linear-gradient(rgba(15, 23, 42, 0.5), rgba(15, 23, 42, 0.5)), url(${backgroundImageUrl})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
          padding: '2rem'
        }}>
          {!showForm && (
            <div className="cyberpunk-text" style={{ maxWidth: '800px' }}>
              <h1 style={{ fontSize: '3.5rem', fontWeight: 'bold', margin: 0 }}>
                WELCOME TO THE<br />
                FRAUD GENERATION<br />
                AND ANALYSIS
              </h1>
            </div>
          )}

          {/* Decorative neon border when in form mode */}
          {showForm && (
            <div style={{
              position: 'absolute',
              top: '2rem',
              left: '2rem',
              right: '2rem',
              bottom: '2rem',
              border: '2px solid #00f3ff',
              boxShadow: 'inset 0 0 20px #00f3ff, 0 0 20px #00f3ff',
              pointerEvents: 'none',
              opacity: 0.3
            }}></div>
          )}
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
